import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { X, MapPin } from 'lucide-react';

// Componente interno para capturar el click en el mapa del modal
function LocationMarker({ position, setPosition }) {
  useMapEvents({
    click(e) {
      setPosition([e.latlng.lat, e.latlng.lng]);
    },
  });
  return position ? <Marker position={position} /> : null;
}

const ModalNuevaSucursal = ({ onClose, onSave }) => {
  const [nombre, setNombre] = useState('');
  const [direccion, setDireccion] = useState('');
  const [coords, setCoords] = useState([-26.816, -65.216]);

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave({ nombre, direccion, coords });
  };

  return (
    <div style={modalOverlay}>
      <div style={modalContent}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
          <h3>Registrar Nueva Sucursal</h3>
          <X onClick={onClose} style={{ cursor: 'pointer' }} />
        </div>

        <form onSubmit={handleSubmit}>
          <label style={labelStyle}>Nombre del Local</label>
          <input 
            type="text" 
            placeholder="Ej: Panadería El Sol" 
            style={inputStyle} 
            required 
            value={nombre}
            onChange={(e) => setNombre(e.target.value)}
          />

          <label style={labelStyle}>Dirección</label>
          <input 
            type="text" 
            placeholder="Ej: Av. Alem 123" 
            style={inputStyle} 
            required 
            value={direccion}
            onChange={(e) => setDireccion(e.target.value)}
          />

          <p style={{ fontSize: '0.85rem', color: '#64748b', marginBottom: '10px' }}>
            <MapPin size={14} /> Haz click en el mapa para ubicar la sucursal:
          </p>

          <div style={{ height: '200px', borderRadius: '10px', overflow: 'hidden', marginBottom: '20px' }}>
            <MapContainer center={coords} zoom={13} style={{ height: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <LocationMarker position={coords} setPosition={setCoords} />
            </MapContainer>
          </div>

          <button type="submit" style={btnSubmitModal}>Guardar Sucursal</button>
        </form>
      </div>
    </div>
  );
};

/* --- ESTILOS DEL MODAL --- */
const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.6)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 };
const modalContent = { background: 'white', padding: '30px', borderRadius: '20px', width: '450px', boxShadow: '0 20px 40px rgba(0,0,0,0.2)' };
const inputStyle = { width: '100%', padding: '12px', marginBottom: '15px', borderRadius: '10px', border: '1px solid #ddd', boxSizing: 'border-box' };
const labelStyle = { display: 'block', marginBottom: '5px', fontWeight: 'bold', fontSize: '0.9rem' };
const btnSubmitModal = { width: '100%', padding: '14px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };

export default ModalNuevaSucursal;
